class Solution:
    def beautifulSubsets(self, nums, k):
        n = len(nums)
        count = 0
        for mask in range(1, 1 << n):
            chosen = []
            for i in range(n):
                if mask & (1 << i):
                    chosen.append(nums[i])
            seen = set()
            ok = True
            for v in chosen:
                if (v - k) in seen or (v + k) in seen:
                    ok = False
                    break
                seen.add(v)
            if ok:
                count += 1
        return count

