from collections import defaultdict, Counter
class Solution:
    def beautifulSubsets(self, nums, k):
        cnt = Counter(nums)
        groups = defaultdict(list)
        for v in cnt:
            groups[v % k].append(v)
        total = 1
        for values in groups.values():
            values.sort()
            m = len(values)
            dp = [0] * (m + 1)
            dp[0] = 1
            for i in range(1, m + 1):
                v = values[i - 1]
                ways_pick = (1 << cnt[v]) - 1
                if i >= 2 and v - values[i - 2] == k:
                    dp[i] = dp[i - 1] + ways_pick * dp[i - 2]
                else:
                    dp[i] = dp[i - 1] + ways_pick * dp[i - 1]
            total *= dp[m]
        return total - 1

