var beautifulSubsets = function(nums, k) {
    const cnt = new Map();
    for (const v of nums) cnt.set(v, (cnt.get(v) || 0) + 1);
    const groups = new Map();
    for (const v of cnt.keys()) {
        const r = ((v % k) + k) % k;
        if (!groups.has(r)) groups.set(r, []);
        groups.get(r).push(v);
    }
    let total = 1;
    for (const values of groups.values()) {
        values.sort((a, b) => a - b);
        const m = values.length;
        const dp = new Array(m + 1).fill(0);
        dp[0] = 1;
        for (let i = 1; i <= m; i++) {
            const v = values[i - 1];
            const waysPick = (1 << cnt.get(v)) - 1;
            if (i >= 2 && v - values[i - 2] === k) {
                dp[i] = dp[i - 1] + waysPick * dp[i - 2];
            } else {
                dp[i] = dp[i - 1] + waysPick * dp[i - 1];
            }
        }
        total *= dp[m];
    }
    return total - 1;
};
